class Solution:
    def maxBuilding(self, n, restrictions):
        cap = [n] * (n + 1)
        cap[1] = 0
        for idi, mh in restrictions:
            if mh < cap[idi]:
                cap[idi] = mh
        h = [0] * (n + 1)
        for i in range(2, n + 1):
            h[i] = min(cap[i], h[i - 1] + 1)
        for i in range(n - 1, 0, -1):
            h[i] = min(h[i], h[i + 1] + 1)
        return max(h[1:])

