class Solution:
    def maxBuilding(self, n, restrictions):
        r = sorted(restrictions)
        r = [[1, 0]] + r
        if not r or r[-1][0] != n:
            r.append([n, n - 1])
        m = len(r)
        for i in range(1, m):
            r[i][1] = min(r[i][1], r[i - 1][1] + (r[i][0] - r[i - 1][0]))
        for i in range(m - 2, -1, -1):
            r[i][1] = min(r[i][1], r[i + 1][1] + (r[i + 1][0] - r[i][0]))
        ans = 0
        for i in range(1, m):
            left = r[i - 1][1]
            right = r[i][1]
            dist = r[i][0] - r[i - 1][0]
            peak = (left + right + dist) // 2
            if peak > ans:
                ans = peak
        return ans

