var maxBuilding = function(n, restrictions) {
    const r = restrictions.map(x => x.slice()).sort((a, b) => a[0] - b[0]);
    r.unshift([1, 0]);
    if (r[r.length - 1][0] !== n) r.push([n, n - 1]);
    const m = r.length;
    for (let i = 1; i < m; i++) {
        r[i][1] = Math.min(r[i][1], r[i - 1][1] + (r[i][0] - r[i - 1][0]));
    }
    for (let i = m - 2; i >= 0; i--) {
        r[i][1] = Math.min(r[i][1], r[i + 1][1] + (r[i + 1][0] - r[i][0]));
    }
    let ans = 0;
    for (let i = 1; i < m; i++) {
        const left = r[i - 1][1];
        const right = r[i][1];
        const dist = r[i][0] - r[i - 1][0];
        const peak = Math.floor((left + right + dist) / 2);
        if (peak > ans) ans = peak;
    }
    return ans;
};
